// frontend/src/pages/Dashboard.jsx
import React, { useState, useEffect, useCallback } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import {
  PieChart, Pie, Cell, Tooltip, ResponsiveContainer, Legend,
  BarChart, Bar, XAxis, YAxis, CartesianGrid,
} from 'recharts';
import { getDashboardStats, predictChurn } from '../api';

const COLORS = ['#f43f5e', '#10b981'];

const FIELDS = [
  { name:'gender',          label:'Genre',           type:'select',   opts:['Male','Female'] },
  { name:'SeniorCitizen',   label:'Senior',          type:'select',   opts:[{label:'Non',val:0},{label:'Oui',val:1}], isInt:true },
  { name:'tenure',          label:'Ancienneté (mois)',type:'number' },
  { name:'MonthlyCharges',  label:'Charges mensuelles',type:'number' },
  { name:'TotalCharges',    label:'Charges totales', type:'text' },
  { name:'Contract',        label:'Contrat',         type:'select',   opts:['Month-to-month','One year','Two year'] },
  { name:'InternetService', label:'Internet',        type:'select',   opts:['DSL','Fiber optic','No'] },
  { name:'PaymentMethod',   label:'Paiement',        type:'select',   opts:['Electronic check','Mailed check','Bank transfer (automatic)','Credit card (automatic)'] },
  { name:'TechSupport',     label:'Support tech',    type:'select',   opts:['Yes','No','No internet service'] },
  { name:'OnlineSecurity',  label:'Sécurité online', type:'select',   opts:['Yes','No','No internet service'] },
];

export default function Dashboard() {
  const [stats, setStats]       = useState(null);
  const [loading, setLoading]   = useState(true);
  const [form, setForm]         = useState({});
  const [result, setResult]     = useState(null);
  const [predLoading, setPredLoading] = useState(false);
  const navigate = useNavigate();

  const load = useCallback(async () => {
    try {
      const res = await getDashboardStats();
      setStats(res.data);
    } catch {
      /* empty DB is fine */
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { load(); }, [load]);

  const logout = () => { localStorage.removeItem('token'); navigate('/login'); };

  const handleChange = (name, value) => setForm(f => ({ ...f, [name]: value }));

  const handlePredict = async (e) => {
    e.preventDefault();
    setPredLoading(true);
    setResult(null);
    try {
      const payload = { ...form };
      FIELDS.forEach(f => {
        if (f.isInt && payload[f.name] !== undefined) payload[f.name] = parseInt(payload[f.name]);
        if (f.type === 'number' && payload[f.name] !== undefined) payload[f.name] = parseFloat(payload[f.name]);
      });
      const res = await predictChurn(payload);
      setResult(res.data);
      load(); // refresh stats
    } catch (err) {
      setResult({ error: err.response?.data?.detail || 'Erreur de prédiction' });
    } finally {
      setPredLoading(false);
    }
  };

  const pieData = stats
    ? [
        { name: 'Churn', value: stats.churn_count },
        { name: 'Fidèles', value: stats.no_churn_count },
      ]
    : [];

  const sentimentColor = stats
    ? stats.avg_sentiment > 0.65 ? 'var(--success)'
    : stats.avg_sentiment < 0.35 ? 'var(--danger)'
    : 'var(--warning)'
    : 'var(--text2)';

  return (
    <div className="layout">
      <Sidebar active="dashboard" onLogout={logout} />

      <div className="main">
        <div className="page-header">
          <div>
            <h2>Dashboard</h2>
            <p>Vue globale des prédictions et de l'activité</p>
          </div>
          <button className="btn btn-ghost btn-sm" onClick={load} id="refresh-btn">
            ↻ Rafraîchir
          </button>
        </div>

        <div className="page-content">
          {/* ─── STATS ─── */}
          <div className="stats-grid">
            <div className="stat-card purple">
              <div className="stat-label">Total prédictions</div>
              <div className="stat-value">{loading ? '—' : stats?.total_predictions ?? 0}</div>
              <div className="stat-sub">depuis le début</div>
            </div>
            <div className="stat-card red">
              <div className="stat-label">Taux de churn</div>
              <div className="stat-value">
                {loading ? '—' : `${((stats?.churn_rate ?? 0) * 100).toFixed(1)}%`}
              </div>
              <div className="stat-sub">{stats?.churn_count ?? 0} clients à risque</div>
            </div>
            <div className="stat-card green">
              <div className="stat-label">Feedbacks</div>
              <div className="stat-value">{loading ? '—' : stats?.total_feedbacks ?? 0}</div>
              <div className="stat-sub">commentaires reçus</div>
            </div>
            <div className="stat-card amber">
              <div className="stat-label">Sentiment moyen</div>
              <div className="stat-value" style={{ color: sentimentColor, fontSize: '1.6rem' }}>
                {loading ? '—' : stats?.avg_sentiment != null
                  ? stats.avg_sentiment > 0.65 ? '😊 Positif'
                  : stats.avg_sentiment < 0.35 ? '😞 Négatif'
                  : '😐 Neutre'
                  : 'N/A'}
              </div>
              <div className="stat-sub">
                {stats?.avg_sentiment != null ? `score: ${(stats.avg_sentiment * 100).toFixed(0)}%` : ''}
              </div>
            </div>
          </div>

          {/* ─── CHARTS + PREDICT FORM ─── */}
          <div className="grid-2" style={{ marginBottom: '24px' }}>
            {/* Pie chart */}
            <div className="card">
              <div className="chart-title">Répartition Churn / Fidèles</div>
              {stats && stats.total_predictions > 0 ? (
                <ResponsiveContainer width="100%" height={220}>
                  <PieChart>
                    <Pie data={pieData} cx="50%" cy="50%" innerRadius={60} outerRadius={90} paddingAngle={4} dataKey="value">
                      {pieData.map((_, i) => <Cell key={i} fill={COLORS[i]} />)}
                    </Pie>
                    <Tooltip
                      contentStyle={{ background: 'var(--surface2)', border: '1px solid var(--border)', borderRadius: 8 }}
                      labelStyle={{ color: 'var(--text)' }}
                    />
                    <Legend />
                  </PieChart>
                </ResponsiveContainer>
              ) : (
                <div className="empty-state">
                  <p>Aucune prédiction encore effectuée.</p>
                </div>
              )}
            </div>

            {/* Bar chart */}
            <div className="card">
              <div className="chart-title">Résumé des métriques</div>
              {stats && stats.total_predictions > 0 ? (
                <ResponsiveContainer width="100%" height={220}>
                  <BarChart data={[
                    { name: 'Prédictions', val: stats.total_predictions },
                    { name: 'Churns', val: stats.churn_count },
                    { name: 'Fidèles', val: stats.no_churn_count },
                    { name: 'Feedbacks', val: stats.total_feedbacks },
                  ]} barSize={32}>
                    <CartesianGrid strokeDasharray="3 3" stroke="var(--border)" />
                    <XAxis dataKey="name" tick={{ fill: 'var(--text2)', fontSize: 12 }} axisLine={false} tickLine={false} />
                    <YAxis tick={{ fill: 'var(--text3)', fontSize: 11 }} axisLine={false} tickLine={false} />
                    <Tooltip
                      contentStyle={{ background: 'var(--surface2)', border: '1px solid var(--border)', borderRadius: 8 }}
                    />
                    <Bar dataKey="val" fill="var(--accent)" radius={[6,6,0,0]} />
                  </BarChart>
                </ResponsiveContainer>
              ) : (
                <div className="empty-state"><p>Les données s'afficheront après la première prédiction.</p></div>
              )}
            </div>
          </div>

          {/* ─── PREDICT FORM ─── */}
          <div className="card">
            <div className="section-title">🔮 Prédiction rapide</div>
            <form onSubmit={handlePredict}>
              <div className="grid-3">
                {FIELDS.map(f => (
                  <div className="form-group" key={f.name}>
                    <label>{f.label}</label>
                    {f.type === 'select' ? (
                      <select
                        id={`pred-${f.name}`}
                        className="form-control"
                        value={form[f.name] ?? ''}
                        onChange={e => handleChange(f.name, f.isInt ? parseInt(e.target.value) : e.target.value)}
                      >
                        <option value="">-- Choisir --</option>
                        {f.opts.map(o =>
                          typeof o === 'object'
                            ? <option key={o.val} value={o.val}>{o.label}</option>
                            : <option key={o} value={o}>{o}</option>
                        )}
                      </select>
                    ) : (
                      <input
                        id={`pred-${f.name}`}
                        type={f.type}
                        className="form-control"
                        placeholder={f.label}
                        value={form[f.name] ?? ''}
                        onChange={e => handleChange(f.name, e.target.value)}
                      />
                    )}
                  </div>
                ))}
              </div>

              <button id="predict-btn" type="submit" className="btn btn-primary" disabled={predLoading}>
                {predLoading ? <span className="spinner" /> : '⚡'}
                {predLoading ? 'Analyse...' : 'Prédire le churn'}
              </button>
            </form>

            {result && !result.error && (
              <div className={`result-box ${result.risk_level}`}>
                <div className="risk-label">Niveau de risque</div>
                <div className="risk-value">
                  {result.risk_level === 'high'   && '🔴 Risque élevé'}
                  {result.risk_level === 'medium'  && '🟡 Risque modéré'}
                  {result.risk_level === 'low'     && '🟢 Faible risque'}
                </div>
                <div className="prob-bar-wrap">
                  <div style={{ display:'flex', justifyContent:'space-between', marginBottom:4, fontSize:'0.8rem', color:'var(--text2)' }}>
                    <span>Probabilité de churn</span>
                    <span>{(result.probability * 100).toFixed(1)}%</span>
                  </div>
                  <div className="prob-bar-bg">
                    <div
                      className={`prob-bar-fill ${result.risk_level}`}
                      style={{ width: `${result.probability * 100}%` }}
                    />
                  </div>
                </div>
              </div>
            )}

            {result?.error && (
              <div className="error-msg" style={{ marginTop: 12 }}>⚠️ {result.error}</div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

// ─── SHARED SIDEBAR ────────────────────────────────────────────────────
export function Sidebar({ active, onLogout }) {
  const navItems = [
    { id: 'dashboard', icon: '📊', label: 'Dashboard', to: '/dashboard' },
    { id: 'clients',   icon: '👥', label: 'Clients',   to: '/clients'   },
  ];

  return (
    <aside className="sidebar">
      <div className="sidebar-brand">
        <h1>⚡ ChurnGuard</h1>
        <p>ML Platform v1.0</p>
      </div>
      <nav className="sidebar-nav">
        {navItems.map(item => (
          <Link
            key={item.id}
            to={item.to}
            className={`nav-item ${active === item.id ? 'active' : ''}`}
            id={`nav-${item.id}`}
          >
            <span>{item.icon}</span>
            {item.label}
          </Link>
        ))}
      </nav>
      <div className="sidebar-footer">
        <button id="logout-btn" className="nav-item" style={{color:'var(--danger)'}} onClick={onLogout}>
          <span>🚪</span> Déconnexion
        </button>
      </div>
    </aside>
  );
}
